from dwh_ctmdb.calls as c
left join dwh_ctmdb.transcriptions as t on t.call_id = c.call_id
left join dwh_ctmdb.call_summary as s on s.call_id = c.call_id
where 
	(source like 
		-- "%goodzer%" -- or source like
        -- "%pestnet%" -- or source like
        -- "%consumer%" -- or source like 
        "%biz%" -- or source like 
        -- "%lsa%" or source like "%local service ad%"
	)
    # Date filter
	and c.called_at_utc between date_sub(curdate(), interval 3 month) and curdate() 
	# Bilability filter
    and c.sale_billable = "non billable"